const allTrends = $input.all();

// Get used trends from Get Used Trends (deduplicate by id)
let usedTrendsItems = [];
try {
  const raw = $node["Get Used Trends"].all();
  // Deduplicate by id - keeps only first occurrence of each id
  const seen = new Set();
  usedTrendsItems = raw.filter(item => {
    const id = item.json.id;
    if (seen.has(id)) return false;
    seen.add(id);
    return true;
  });
} catch (e) {
  usedTrendsItems = [];
}

const oneDay = 24 * 60 * 60 * 1000;
const now = new Date();

const recentUsed = usedTrendsItems
  .filter(item => {
    if (!item.json.date) return false;
    const d = new Date(item.json.date);
    if (isNaN(d.getTime())) return false;
    return (now - d) < oneDay;
  })
  .map(item => (item.json.trend || "").trim().toLowerCase());

const availableTrends = allTrends.filter(item => {
  const trend = (item.json.trend || "").trim().toLowerCase();
  return !recentUsed.includes(trend);
});

return availableTrends.map(item => ({ json: { trend: item.json.trend } }));

const items = $input.all();

// Pick the first 2 trends from the list
const picked = items.slice(0, 2);

return picked.map(item => ({
