  }
}));

// Get the current trend from the loop (passed through Loop Over Items)
const currentTrend = $('Loop Over Items').item.json.trend;

return [{
  json: {
    trend: currentTrend,
    tweet: $input.first().json.content[0].text.text,
    usedAt: new Date().toISOString()
  }
}];

const items = $input.all();

const firstItem = items[0]?.json;
if (!firstItem || firstItem.error) {
  return [{ json: { success: false, error: firstItem?.error || "No data received" } }];
}

const seen = new Set();
const trends = items.flatMap(item => {
  const data = item.json;
  const records = Array.isArray(data) ? data : [data];
  return records
    .map(record => record.title?.trim())
    .filter(title => {
      if (!title || seen.has(title)) return false;
      seen.add(title);
      return true;
    })
    .map(title => ({ json: { trend: title } }));
});

if (trends.length === 0) {
  return [{ json: { success: false, error: "No valid trend data found" } }];
}

return [{ json: { success: true, trends } }];

const trends = $json.trends;

return trends.map(trend => ({
  json: { trend }
}));

