const content = $json.content;

// Handle direct text response
if (content?.parts?.[0]?.text) {
  return [{ json: { tweet: content.parts[0].text } }];
}

// Handle when Gemini used a tool/function call - text may be in a different part
if (Array.isArray(content?.parts)) {
  const textPart = content.parts.find(p => p.text);
  if (textPart) {
    return [{ json: { tweet: textPart.text } }];
  }
}

// Fallback: check candidates structure (some Gemini versions return this)
if ($json.candidates?.[0]?.content?.parts?.[0]?.text) {
  return [{ json: { tweet: $json.candidates[0].content.parts[0].text } }];
}

throw new Error('Could not extract tweet text from Gemini response. Raw: ' + JSON.stringify($json).slice(0, 300));

